"C:\\WINDOWS\\System32\\WindowsPowerShell\\v1.0\\powershell.exe" -Command "@'
"'$ErrorActionPreference = '"'Stop'
"'$base = '"'demo/automation_poller/daily_notes_doc/fixtures/workspace/memory/doc/daily-note-derived'
"'$files = @('"'current-state.md','decisions.md','open-questions.md','source-map.md')
foreach ("'$file in $files) {
  $path = Join-Path $base $file
  $content = Get-Content -Raw $path
  [regex]::Matches($content, '"'\\((\\.\\./\\.\\./daily-notes/["'^)]+'"\\.md)\\)') | ForEach-Object {
    "'$rel = $_.Groups[1].Value
    $target = [System.IO.Path]::GetFullPath((Join-Path (Split-Path $path) $rel))
    [pscustomobject]@{ file=$file; rel=$rel; exists=(Test-Path $target); target=$target }
  }
}
'"'@ | powershell -NoProfile -Command -"

"C:\\WINDOWS\\System32\\WindowsPowerShell\\v1.0\\powershell.exe" -Command "@'
"'$ErrorActionPreference = '"'Stop'
"'$path = '"'demo/automation_poller/daily_notes_doc/fixtures/workspace/memory/doc/daily-note-derived/source-map.md'
"'$content = Get-Content -Raw $path
$lines = $content -split "`r?`n"
$rows = @()
foreach ($line in $lines) {
  if ($line -match '"'"'^'"\\| \\[(?<note>["'^'"\\]]+)\\]\\(\\.\\./\\.\\./daily-notes/["'^)]+'"\\.md\\) \\|') {
    "'$rows += $matches['"'note']
  }
}
"'$dupes = $rows | Group-Object | Where-Object { $_.Count -gt 1 } | Select-Object -ExpandProperty Name
[pscustomobject]@{
  rows = $rows -join '"','
  duplicates = "'$dupes -join '"','
}
'@ | powershell -NoProfile -Command -"

